INSERT INTO image_files ( file_name, creation_date, modification_date, last_access_time, file_format, file_size, file_md5, file_path, width, height, folder_name, actor, score, create_time ) VALUES
(#{item.fileName}, #{item.creationDate}, #{item.modificationDate}, #{item.lastAccessTime}, #{item.fileFormat}, #{item.fileSize}, #{item.fileMd5}, #{item.filePath}, #{item.width}, #{item.height}, #{item.folderName}, #{item.actor}, #{item.score}, #{item.createTime})
ON DUPLICATE KEY UPDATE file_name = VALUES(file_name), creation_date = VALUES(creation_date), modification_date = VALUES(modification_date), last_access_time = VALUES(last_access_time), file_format = VALUES(file_format), file_size = VALUES(file_size), file_md5 = VALUES(file_md5), width = VALUES(width), height = VALUES(height), folder_name = VALUES(folder_name), actor = VALUES(actor), score = VALUES(score), create_time = VALUES(create_time);
